const expected = String($env.N8N_TELEGRAM_WEBHOOK_SECRET || '');
const headers = $json.headers || {};
const actual = String(headers['x-telegram-bot-api-secret-token'] || headers['X-Telegram-Bot-Api-Secret-Token'] || '');
if (expected && actual !== expected) {
  return [];
}
const update = $json.body || $json;
return [{ json: update }];

const update = $json;
const callback = update.callback_query || null;
const message = callback?.message || update.message || update.edited_message || {};
const from = callback?.from || message.from || {};
const chat = message.chat || {};
const text = callback?.data || message.text || message.caption || '';
if (!chat.id || !text) return [];
return [{ json: {
  updateId: update.update_id,
  chatId: String(chat.id),
  userId: String(from.id || ''),
  username: from.username || [from.first_name, from.last_name].filter(Boolean).join(' '),
  text,
  callbackQueryId: callback?.id || null,
  isCallback: Boolean(callback)
}}];
